const item = $input.item.json;

const subject = (item.subject ?? '').toLowerCase();
const body = item.body_text ?? '';

// Filtrar correus automàtics que no aporten valor analitzable
const SKIP_PATTERNS = [
  /^aceptad[oa]:/i,
  /^rechazad[oa]:/i,
  /^accepted:/i,
  /^declined:/i,
  /^tentative:/i,
  /^invitation:/i,
  /^invitaci[oó]n:/i,
  /^updated invitation/i,
  /^canceled event/i,
  /^evento cancelado/i,
  /^out of office/i,
  /^fuera de (la )?oficina/i,
  /^automatic reply/i,
  /^respuesta autom[aá]tica/i,
  /^undelivered mail/i,
  /^delivery status/i,
  /^mail delivery failed/i,
  /^re:.*noreply/i,
];

const shouldSkip = SKIP_PATTERNS.some(p => p.test(item.subject ?? ''));
if (shouldSkip) return [];

// Truncar body
const MAX_BODY_CHARS = 12000;
const bodyTrunc = body.substring(0, MAX_BODY_CHARS);
const wasTruncated = body.length > MAX_BODY_CHARS;

const sentAt = item.sent_at
  ? new Date(item.sent_at).toLocaleDateString('es-ES', { year: 'numeric', month: 'long', day: 'numeric' })
  : 'desconocida';

const prompt = `Analiza el siguiente contenido de comunicación empresarial.
Responde EXCLUSIVAMENTE en JSON válido con esta estructura exacta, sin ningún texto adicional fuera del JSON:
{
  "summary": "resumen breve en 1-2 frases del contenido",
  "sentiment_label": "positive" | "neutral" | "negative" | "mixed",
  "sentiment_score": número entre -1.0 y 1.0,
  "complaint_flag": true o false,
  "satisfaction_flag": true o false,
  "needs_follow_up": true o false,
  "urgency_score": número entre 0.0 y 1.0,
  "topics": ["topic1", "topic2"],
  "risks": ["riesgo1", "riesgo2"],
  "action_items": [{"text": "descripción de la acción", "priority": "low|medium|high|critical"}]
}

Tipo: ${item.entity_type === 'email_message' ? 'Email' : 'Transcripción de reunión'}
Asunto: ${(item.subject ?? '').substring(0, 200)}
Dirección: ${item.direction}
Fecha: ${sentAt}${wasTruncated ? '\n[Contenido truncado a los primeros 12.000 caracteres]' : ''}

Contenido:
${bodyTrunc}`;

return [{
  json: {
    ...item,
    prompt,
    body_truncated: wasTruncated
  }
}];

const ctx      = $('Build prompt').item.json;
const aiOutput = $input.item.json;

// Extract text — adapt to actual OpenAI response structure
const rawText = aiOutput?.output?.[0]?.content?.[0]?.text
  ?? aiOutput?.message?.content
  ?? aiOutput?.choices?.[0]?.message?.content
  ?? '';

// Parse and validate
let parsed;
try {
  const cleaned = rawText.replace(/^```json\s*/i, '').replace(/```\s*$/i, '').trim();
  parsed = JSON.parse(cleaned);
} catch (err) {
  console.error(`[AI Analysis] JSON parse failed for entity ${ctx.entity_id}: ${err.message}`);
  return [];
}

const VALID_SENTIMENTS = ['positive', 'neutral', 'negative', 'mixed'];
const VALID_PRIORITIES = ['low', 'medium', 'high', 'critical'];

const validated = {
  summary:           typeof parsed.summary          === 'string'  ? parsed.summary.substring(0, 1000) : '',
  sentiment_label:   VALID_SENTIMENTS.includes(parsed.sentiment_label) ? parsed.sentiment_label : 'neutral',
  sentiment_score:   typeof parsed.sentiment_score  === 'number'  ? Math.max(-1, Math.min(1, parsed.sentiment_score)) : 0,
  complaint_flag:    typeof parsed.complaint_flag   === 'boolean' ? parsed.complaint_flag    : false,
  satisfaction_flag: typeof parsed.satisfaction_flag === 'boolean' ? parsed.satisfaction_flag : false,
  needs_follow_up:   typeof parsed.needs_follow_up  === 'boolean' ? parsed.needs_follow_up   : false,
  urgency_score:     typeof parsed.urgency_score    === 'number'  ? Math.max(0, Math.min(1, parsed.urgency_score)) : 0,
  topics:            Array.isArray(parsed.topics)    ? parsed.topics.filter(t => typeof t === 'string').slice(0, 20) : [],
  risks:             Array.isArray(parsed.risks)     ? parsed.risks.filter(r => typeof r === 'string').slice(0, 20)  : [],
  action_items:      Array.isArray(parsed.action_items)
    ? parsed.action_items
        .filter(a => a && typeof a.text === 'string')
        .map(a => ({
          text:     a.text.substring(0, 500),
          priority: VALID_PRIORITIES.includes(a.priority) ? a.priority : 'medium'
        }))
        .slice(0, 20)
    : []
};

return [{
  json: {
    entity_id:   ctx.entity_id,
    entity_type: ctx.entity_type,
    client_id:   ctx.client_id,
    subject:     ctx.subject,
    ...validated,
    raw_output: parsed,
    is_high_risk: validated.complaint_flag || validated.urgency_score >= 0.8
  }
}];

// Expand action_items → one item per action, skipping if none
const insight    = $('Validate + parse response').item.json;
const insightRow = $input.item.json;

if (!insight.action_items?.length) return [];

return insight.action_items.map(a => ({
  json: {
    insight_id: insightRow.insight_id,
    client_id:  insight.client_id,
    text:       a.text,
    priority:   a.priority
  }
}));

const insight     = $('Validate + parse response').item.json;
const clientRow   = $input.item.json;

const clientName  = clientRow?.client_name ?? 'Client desconegut';
const entityLabel = insight.entity_type === 'email_message' ? '📧 Email' : '📝 Transcript';
const flags       = [];
if (insight.complaint_flag)       flags.push('⚠️ Queixa detectada');
if (insight.urgency_score >= 0.8) flags.push(`🔴 Urgència: ${(insight.urgency_score * 100).toFixed(0)}%`);
if (insight.needs_follow_up)      flags.push('🔁 Requereix seguiment');

const topicsStr = insight.topics?.length ? insight.topics.slice(0, 5).join(', ') : '—';
const risksStr  = insight.risks?.length  ? insight.risks.slice(0, 3).join(' | ')  : '—';

const slackText = [
  `*🚨 Alerta d'alt risc — ${clientName}*`,
  `${entityLabel} · Assumpte: _${(insight.subject ?? '').substring(0, 100)}_`,
  '',
  `*Resum:* ${insight.summary}`,
  `*Indicadors:* ${flags.join(' · ')}`,
  `*Temes:* ${topicsStr}`,
  `*Riscos:* ${risksStr}`
].join('\n');

return [{
  json: {
    slack_text:   slackText,
    client_name:  clientName,
    insight
  }
}];
